        <button onClick={()=>window.open("https://pay.wave.com/m/M_OfXoINLDFRLm/c/ci/")} className="tap"
          style={{width:"100%",background:"#1BA8E022",color:"#1BA8E0",border:`1px solid #1BA8E044`,borderRadius:12,padding:"12px",fontWeight:700,fontSize:14}}>
          〽️ Payer via Wave
        </button>
