// ══ STOCKS ════════════════════════════════════════════════════════
function Stocks(){
  const [stocks,setStocks]=useState([
    {id:1,tissu:"Bazin Champagne",qte:15,unite:"mètres",prix:3500,alerte:5,color:"#C09858"},
    {id:2,tissu:"Bazin Bleu Roi",qte:8,unite:"mètres",prix:3500,alerte:5,color:"#203888"},
    {id:3,tissu:"Wax Orange",qte:20,unite:"mètres",prix:2500,alerte:8,color:"#C86010"},
    {id:4,tissu:"Wax Multicolor",qte:12,unite:"mètres",prix:2800,alerte:6,color:"#D4A853"},
    {id:5,tissu:"Dentelle Violette",qte:3,unite:"mètres",prix:5000,alerte:4,color:"#8040A8"},
    {id:6,tissu:"Mousseline Blanche",qte:25,unite:"mètres",prix:2000,alerte:8,color:"#F0E8D8"},
    {id:7,tissu:"Soie Rose",qte:6,unite:"mètres",prix:6000,alerte:4,color:"#D06080"},
    {id:8,tissu:"Kente Ghana",qte:4,unite:"mètres",prix:8000,alerte:3,color:"#C89800"},
  ]);
  const [modal,setModal]=useState(false);
  const [form,setForm]=useState({tissu:"",qte:"",unite:"mètres",prix:"",alerte:"5",color:"#D4A853"});

  const save=()=>{
    if(!form.tissu.trim())return;
    setStocks(p=>[...p,{...form,id:gid(p),qte:+form.qte,prix:+form.prix,alerte:+form.alerte}]);
    setModal(false);
    setForm({tissu:"",qte:"",unite:"mètres",prix:"",alerte:"5",color:"#D4A853"});
  };

  const update=(id,delta)=>setStocks(p=>p.map(s=>s.id===id?{...s,qte:Math.max(0,s.qte+delta)}:s));
  const alertes=stocks.filter(s=>s.qte<=s.alerte);

  return(
    <div className="up">
      {alertes.length>0&&(
        <div style={{background:C.red+"22",border:`1px solid ${C.red}44`,borderRadius:14,padding:14,marginBottom:16}}>
          <div style={{color:C.red,fontWeight:700,fontSize:14,marginBottom:8}}>⚠️ Stock faible ({alertes.length} tissu{alertes.length>1?"s":""})</div>
          {alertes.map(s=><div key={s.id} style={{color:C.cream,fontSize:13}}>• {s.tissu} : {s.qte} {s.unite} restant{s.qte>1?"s":""}</div>)}
        </div>
      )}

      <button onClick={()=>setModal(true)} className="tap" style={{width:"100%",background:`linear-gradient(90deg,${C.terra},${C.gold})`,color:"#fff",border:"none",borderRadius:12,padding:13,fontWeight:700,fontSize:15,marginBottom:14}}>+ Ajouter un tissu</button>

      {stocks.map(s=>{
        const bas=s.qte<=s.alerte;
        return(
          <Card key={s.id}>
            <Row style={{alignItems:"center",gap:12}}>
              <div style={{width:44,height:44,borderRadius:10,background:s.color,flexShrink:0,border:`2px solid ${s.color}88`}}/>
              <Col style={{flex:1}}>
                <div style={{color:C.cream,fontWeight:600,fontSize:14}}>{s.tissu}</div>
                <div style={{color:C.dim,fontSize:12,marginTop:2}}>{fmt(s.prix)}/m · {s.unite}</div>
              </Col>
              <Col style={{alignItems:"flex-end",gap:6}}>
                <div style={{color:bas?C.red:C.green,fontWeight:700,fontSize:16}}>{s.qte}m</div>
                {bas&&<span style={{background:C.red+"22",color:C.red,fontSize:10,padding:"2px 8px",borderRadius:20,fontWeight:600}}>⚠️ Bas</span>}
              </Col>
            </Row>
            <Row style={{gap:8,marginTop:12,justifyContent:"flex-end"}}>
              <button onClick={()=>update(s.id,-1)} className="tap" style={{background:C.red+"22",color:C.red,border:"none",borderRadius:8,padding:"6px 16px",fontWeight:700,fontSize:16}}>−</button>
              <button onClick={()=>update(s.id,+1)} className="tap" style={{background:C.green+"22",color:C.green,border:"none",borderRadius:8,padding:"6px 16px",fontWeight:700,fontSize:16}}>+</button>
            </Row>
          </Card>
        );
      })}

      {modal&&<Modal title="Nouveau tissu" onClose={()=>setModal(false)}>
        <Inp label="Nom du tissu *" value={form.tissu} onChange={e=>setForm({...form,tissu:e.target.value})} placeholder="Ex: Bazin Champagne"/>
        <Row style={{gap:10}}>
          <div style={{flex:1}}><Inp label="Quantité" type="number" value={form.qte} onChange={e=>setForm({...form,qte:e.target.value})} placeholder="0"/></div>
          <div style={{flex:1}}><Inp label="Unité" value={form.unite} onChange={e=>setForm({...form,unite:e.target.value})}/></div>
        </Row>
        <Inp label="Prix/mètre (FCFA)" type="number" value={form.prix} onChange={e=>setForm({...form,prix:e.target.value})} placeholder="0"/>
        <Inp label="Alerte stock bas" type="number" value={form.alerte} onChange={e=>setForm({...form,alerte:e.target.value})}/>
        <Btn ch="✅ Ajouter" onClick={save}/>
      </Modal>}
    </div>
  );
}

// ══ STATS ═════════════════════════════════════════════════════════
function Stats({commandes,paiements,clients}){
  const totalCA=paiements.reduce((s,p)=>s+p.mt,0);
  const totalCmd=commandes.length;
  const cmdLivrees=commandes.filter(c=>c.st==="Livré").length;
  const cmdEnCours=commandes.filter(c=>c.st==="En cours").length;
  const cmdPretes=commandes.filter(c=>c.st==="Prêt").length;
  const reste=commandes.reduce((s,c)=>s+(c.px-c.av),0);
  const ticket=totalCA>0?Math.round(totalCA/paiements.length):0;

  const byMode=["Espèces","Orange Money","MTN Money","Wave","Moov Money"].map(m=>({
    m,t:paiements.filter(p=>p.md===m).reduce((s,p)=>s+p.mt,0)
  })).filter(x=>x.t>0).sort((a,b)=>b.t-a.t);

  const byStat=[
    {l:"En attente",v:commandes.filter(c=>c.st==="En attente").length,c:"#D4A853"},
    {l:"En cours",v:cmdEnCours,c:"#4A8CC4"},
    {l:"Prêt",v:cmdPretes,c:"#3DAA6A"},
    {l:"Livré",v:cmdLivrees,c:"#666"},
    {l:"Annulé",v:commandes.filter(c=>c.st==="Annulé").length,c:"#D94040"},
  ].filter(x=>x.v>0);

  return(
    <div className="up">
      {/* KPIs */}
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:16}}>
        {[
          {l:"Chiffre d'affaires",v:fmt(totalCA),i:"💰",c:C.gold},
          {l:"Reste à encaisser",v:fmt(reste),i:"🔴",c:C.red},
          {l:"Total commandes",v:totalCmd,i:"📋",c:C.blue},
          {l:"Clients fidèles",v:clients.length,i:"👥",c:C.terra},
          {l:"Ticket moyen",v:fmt(ticket),i:"🧾",c:C.green},
          {l:"Taux livraison",v:totalCmd>0?Math.round(cmdLivrees/totalCmd*100)+"%":"0%",i:"🚚",c:"#9B59B6"},
        ].map(s=>(
          <Card key={s.l} style={{textAlign:"center",padding:"14px 10px"}}>
            <div style={{fontSize:22}}>{s.i}</div>
            <div style={{color:s.c,fontWeight:700,fontSize:15,marginTop:4,lineHeight:1.2}}>{s.v}</div>
            <div style={{color:C.dim,fontSize:11,marginTop:3}}>{s.l}</div>
          </Card>
        ))}
      </div>

      {/* Statuts commandes */}
      <Card style={{marginBottom:16}}>
        <div style={{color:C.gold,fontWeight:700,marginBottom:14}}>📊 Commandes par statut</div>
        {byStat.map(s=>{
          const pct=totalCmd>0?Math.round(s.v/totalCmd*100):0;
          return(
            <div key={s.l} style={{marginBottom:10}}>
              <Row style={{justifyContent:"space-between",marginBottom:4}}>
                <div style={{color:C.cream,fontSize:13}}>{s.l}</div>
                <div style={{color:s.c,fontWeight:700,fontSize:13}}>{s.v} ({pct}%)</div>
              </Row>
              <div style={{height:6,background:C.surface,borderRadius:3,overflow:"hidden"}}>
                <div style={{height:"100%",width:`${pct}%`,background:s.c,borderRadius:3,transition:"width 0.5s"}}/>
              </div>
            </div>
          );
        })}
      </Card>

      {/* Modes de paiement */}
      {byMode.length>0&&(
        <Card>
          <div style={{color:C.gold,fontWeight:700,marginBottom:14}}>💳 Paiements par mode</div>
          {byMode.map(x=>{
            const pct=totalCA>0?Math.round(x.t/totalCA*100):0;
            return(
              <div key={x.m} style={{marginBottom:10}}>
                <Row style={{justifyContent:"space-between",marginBottom:4}}>
                  <div style={{color:C.cream,fontSize:13}}>{x.m}</div>
                  <div style={{color:C.green,fontWeight:700,fontSize:13}}>{fmt(x.t)} ({pct}%)</div>
                </Row>
                <div style={{height:6,background:C.surface,borderRadius:3,overflow:"hidden"}}>
                  <div style={{height:"100%",width:`${pct}%`,background:C.green,borderRadius:3}}/>
                </div>
              </div>
            );
          })}
        </Card>
      )}
    </div>
  );
}

// ══ FIDELITE ══════════════════════════════════════════════════════
function Fidelite({clients,commandes}){
  const getPoints=id=>commandes.filter(c=>c.cid===id&&c.st==="Livré").length*10;
  const getNiveau=pts=>pts>=50?"⭐⭐⭐ VIP":pts>=20?"⭐⭐ Or":pts>=10?"⭐ Argent":"Bronze";
  const getCouleur=pts=>pts>=50?C.gold:pts>=20?"#C09858":pts>=20?"#C0C0C0":"#CD7F32";

  return(
    <div className="up">
      <Card style={{background:`linear-gradient(135deg,${C.terra}18,${C.gold}18)`,border:`1px solid ${C.gold}33`,marginBottom:16,textAlign:"center",padding:20}}>
        <div style={{fontSize:32,marginBottom:8}}>🏆</div>
        <div style={{fontFamily:"'Cormorant Garamond',serif",fontSize:20,color:C.gold,fontWeight:700}}>Programme Fidélité</div>
        <div style={{color:C.dim,fontSize:13,marginTop:6}}>10 points par commande livrée · Réductions exclusives</div>
      </Card>

      <div style={{marginBottom:16}}>
        <Card style={{padding:"12px 16px",marginBottom:8,background:C.surface}}>
          <div style={{color:C.cream,fontWeight:600,marginBottom:6}}>🎁 Avantages par niveau</div>
          {[["Bronze","0-9 pts","Accès catalogue","#CD7F32"],["⭐ Argent","10-19 pts","5% de remise","#A0A0A0"],["⭐⭐ Or","20-49 pts","10% de remise","#C09858"],["⭐⭐⭐ VIP","50+ pts","15% + priorité","#D4A853"]].map(([n,p,a,c])=>(
            <Row key={n} style={{justifyContent:"space-between",padding:"6px 0",borderBottom:`1px solid ${C.card}`}}>
              <div style={{color:c,fontWeight:600,fontSize:13}}>{n}</div>
              <div style={{color:C.dim,fontSize:12}}>{p}</div>
              <div style={{color:C.cream,fontSize:12}}>{a}</div>
            </Row>
          ))}
        </Card>
      </div>

      {clients.map(c=>{
        const pts=getPoints(c.id);
        const niv=getNiveau(pts);
        const col=getCouleur(pts);
        const nbCmd=commandes.filter(x=>x.cid===c.id).length;
        return(
          <Card key={c.id}>
            <Row style={{alignItems:"center",gap:14}}>
              <div style={{width:46,height:46,borderRadius:"50%",background:`linear-gradient(135deg,${col},${C.gold})`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,fontWeight:700,color:"#0F0A05",flexShrink:0}}>{c.nom[0]}</div>
              <Col style={{flex:1}}>
                <div style={{color:C.cream,fontWeight:600}}>{c.nom}</div>
                <div style={{color:col,fontSize:13,fontWeight:600,marginTop:2}}>{niv}</div>
                <div style={{color:C.dim,fontSize:12,marginTop:2}}>{nbCmd} commande{nbCmd>1?"s":""} · {pts} points</div>
              </Col>
              <div style={{textAlign:"center"}}>
                <div style={{color:col,fontWeight:800,fontSize:22}}>{pts}</div>
                <div style={{color:C.dim,fontSize:10}}>pts</div>
              </div>
            </Row>
            <div style={{marginTop:10}}>
              <div style={{height:6,background:C.surface,borderRadius:3,overflow:"hidden"}}>
                <div style={{height:"100%",width:`${Math.min(100,pts/50*100)}%`,background:`linear-gradient(90deg,${col},${C.gold})`,borderRadius:3}}/>
              </div>
              <div style={{color:C.dim,fontSize:11,marginTop:4,textAlign:"right"}}>{Math.max(0,50-pts)} pts pour VIP</div>
            </div>
          </Card>
        );
      })}
    </div>
  );
}

// ══ AVIS ══════════════════════════════════════════════════════════
function Avis(){
  const [avis,setAvis]=useState([
    {id:1,nom:"Aminata K.",note:5,txt:"Superbe travail ! Mon kaftan était magnifique pour mon mariage. Hamed est très professionnel.",date:"2026-03-20"},
    {id:2,nom:"Moussa C.",note:5,txt:"Senator parfaitement taillé, livré à temps. Je recommande vivement l'atelier Hamed Traoré !",date:"2026-03-15"},
    {id:3,nom:"Fatoumata B.",note:4,txt:"Belle qualité de tissu et coupe impeccable. Très satisfaite de mon boubou de cérémonie.",date:"2026-03-10"},
    {id:4,nom:"Kadiatou T.",note:5,txt:"Le meilleur couturier de Dabakala ! Mes kaftans sont toujours sublimes. Merci Hamed !",date:"2026-03-05"},
  ]);
  const [modal,setModal]=useState(false);
  const [form,setForm]=useState({nom:"",note:5,txt:""});
  const avg=(avis.reduce((s,a)=>s+a.note,0)/avis.length).toFixed(1);

  const save=()=>{
    if(!form.nom.trim()||!form.txt.trim())return;
    setAvis(p=>[{...form,id:gid(p),date:today()},...p]);
    setModal(false);
    setForm({nom:"",note:5,txt:""});
  };

  return(
    <div className="up">
      <Card style={{textAlign:"center",padding:24,background:`linear-gradient(135deg,${C.gold}11,${C.terra}11)`,border:`1px solid ${C.gold}33`,marginBottom:16}}>
        <div style={{fontFamily:"'Cormorant Garamond',serif",fontSize:48,color:C.gold,fontWeight:700}}>{avg}</div>
        <div style={{fontSize:24,marginTop:4}}>{"⭐".repeat(Math.round(avg))}</div>
        <div style={{color:C.dim,fontSize:13,marginTop:6}}>{avis.length} avis clients</div>
      </Card>

      <button onClick={()=>setModal(true)} className="tap" style={{width:"100%",background:`linear-gradient(90deg,${C.terra},${C.gold})`,color:"#fff",border:"none",borderRadius:12,padding:13,fontWeight:700,fontSize:15,marginBottom:14}}>⭐ Laisser un avis</button>

      {avis.map(a=>(
        <Card key={a.id}>
          <Row style={{justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
            <div style={{color:C.cream,fontWeight:700}}>{a.nom}</div>
            <div style={{fontSize:16}}>{"⭐".repeat(a.note)}</div>
          </Row>
          <div style={{color:C.dim,fontSize:14,lineHeight:1.6,marginBottom:8}}>"{a.txt}"</div>
          <div style={{color:C.dim,fontSize:11}}>{a.date}</div>
        </Card>
      ))}

      {modal&&<Modal title="Laisser un avis" onClose={()=>setModal(false)}>
        <Inp label="Votre nom *" value={form.nom} onChange={e=>setForm({...form,nom:e.target.value})} placeholder="Ex: Aminata K."/>
        <div style={{marginBottom:14}}>
          <div style={{color:C.dim,fontSize:11,marginBottom:8,textTransform:"uppercase",letterSpacing:1.5}}>Note</div>
          <Row style={{gap:8}}>
            {[1,2,3,4,5].map(n=>(
              <button key={n} onClick={()=>setForm({...form,note:n})} style={{flex:1,background:form.note>=n?C.gold+"33":C.surface,border:`1px solid ${form.note>=n?C.gold:C.card}`,borderRadius:8,padding:"10px 0",fontSize:20,cursor:"pointer"}}>⭐</button>
            ))}
          </Row>
        </div>
        <Tx label="Votre avis *" value={form.txt} onChange={e=>setForm({...form,txt:e.target.value})} placeholder="Partagez votre expérience..."/>
        <Btn ch="✅ Publier l'avis" onClick={save}/>
      </Modal>}
    </div>
  );
}

